1	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteStep = { op: "quote"; items: Item[] };
4	type Damage = { itemType: string; amount: number };
5	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer: Customer; steps: Step[] };
8	type QuoteResult = { premium: number };
9	type ClaimResult = { payout: number; remainingCap: number };
10	type StepResult = QuoteResult | ClaimResult;
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE = 0.1;
14	const CURSE_SURCHARGE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT = 0.2;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	
20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const INSURANCE_VALUE: Record<string, number> = {
30	  sword: 1000,
31	  amulet: 600,
32	  staff: 800,
33	  potion: 400,
34	  rune: 250,
35	  moonstone: 250,
36	};
37	
38	const DEDUCTIBLE = 100;
39	const CAP_MULTIPLIER = 2;
40	const REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD = 8;
41	const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;
42	
43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	const BLOCK_SIZE = 3;
45	const BLOCK_PREMIUM = 60;
46	
47	const isBlock = (type: string, count: number): boolean =>
48	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
49	
50	const groupPremium = (type: string, count: number): number =>
51	  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;
52	
53	const countByType = (items: Item[]): Map<string, number> => {
54	  const counts = new Map<string, number>();
55	  for (const { type } of items) counts.set(type, (counts.get(type) ?? 0) + 1);
56	  return counts;
57	};
58	
59	const sumBasePremiumsByGroup = (items: Item[]): number =>
60	  [...countByType(items)].reduce(
61	    (total, [type, count]) => total + groupPremium(type, count),
62	    0,
63	  );
64	
65	const isCursed = (item: Item): boolean => item.cursed === true;
66	const isHighlyEnchanted = (item: Item): boolean =>
67	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
68	const isLoyalCustomer = (customer: Customer): boolean =>
69	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
70	
71	const surchargeOnMatching = (
72	  items: Item[],
73	  predicate: (item: Item) => boolean,
74	  rate: number,
75	): number =>
76	  items
77	    .filter(predicate)
78	    .reduce((total, item) => total + BASE_PREMIUM[item.type] * rate, 0);
79	
80	const perItemSurcharges = (items: Item[]): number =>
81	  surchargeOnMatching(items, isCursed, CURSE_SURCHARGE)
82	  + surchargeOnMatching(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE);
83	
84	const policyWideAdjustments = (policyBase: number, customer: Customer): number => {
85	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
86	  const loyalty = isLoyalCustomer(customer) ? -policyBase * LOYALTY_DISCOUNT : 0;
87	  return firstInsurance + loyalty;
88	};
89	
90	const quotePremiumFor = (customer: Customer, { items }: QuoteStep): QuoteResult => {
91	  const policyBase = sumBasePremiumsByGroup(items);
92	  const total =
93	    policyBase
94	    + perItemSurcharges(items)
95	    + policyWideAdjustments(policyBase, customer)
96	    + PROCESSING_FEE;
97	  return { premium: Math.ceil(total) };
98	};
99	
100	type Policy = { items: Item[]; remainingCap: number };
101	
102	const insuranceSumFor = (items: Item[]): number =>
103	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
104	
105	const createPolicy = ({ items }: QuoteStep): Policy => ({
106	  items,
107	  remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER,
108	});
109	
110	const reimbursementRateFor = (item: Item): number =>
111	  (item.enchantment ?? 0) >= REIMBURSEMENT_HIGH_ENCHANTMENT_THRESHOLD
112	    ? HIGH_ENCHANTMENT_REIMBURSEMENT
113	    : 1;
114	
115	const findItem = (policy: Policy, itemType: string): Item => {
116	  const item = policy.items.find((i) => i.type === itemType);
117	  if (item === undefined) throw new Error(`Item not in policy: ${itemType}`);
118	  return item;
119	};
120	
121	const payoutForDamage = (policy: Policy, damage: Damage): number => {
122	  const item = findItem(policy, damage.itemType);
123	  const reimbursed = damage.amount * reimbursementRateFor(item);
124	  return Math.max(0, reimbursed - DEDUCTIBLE);
125	};
126	
127	const totalPayout = (policy: Policy, damages: Damage[]): number =>
128	  damages.reduce((sum, d) => sum + payoutForDamage(policy, d), 0);
129	
130	const settleClaim = (policy: Policy, { incident }: ClaimStep): ClaimResult => {
131	  const uncapped = totalPayout(policy, incident.damages);
132	  const payout = Math.min(uncapped, policy.remainingCap);
133	  policy.remainingCap -= payout;
134	  return { payout, remainingCap: policy.remainingCap };
135	};
136	
137	export const runScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
138	  const policies: Policy[] = [];
139	  const handle = (step: Step): StepResult => {
140	    if (step.op === "quote") {
141	      policies.push(createPolicy(step));
142	      return quotePremiumFor(customer, step);
143	    }
144	    return settleClaim(policies[step.policy], step);
145	  };
146	  return { results: steps.map(handle) };
147	};
